# Definition for a binary tree node.
class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def isValidBST(self, root: Optional[TreeNode]) -> bool:
        """
        递归验证：每个节点有合法的 (min, max) 范围
        """
        def validate(node, low, high):
            # 空节点是合法的
            if not node:
                return True

            # 当前节点值必须严格在 (low, high) 范围内
            if node.val <= low or node.val >= high:
                return False

            # 递归验证左右子树
            # 左子树：所有值必须 < node.val，所以 high = node.val
            # 右子树：所有值必须 > node.val，所以 low = node.val
            return (validate(node.left, low, node.val) and
                    validate(node.right, node.val, high))

        # 初始范围为负无穷到正无穷
        return validate(root, float('-inf'), float('inf'))


# 中序遍历版本（更简洁，但需理解）
class SolutionInorder:
    def isValidBST(self, root: Optional[TreeNode]) -> bool:
        self.prev_val = None
        self.is_valid = True

        def inorder(node):
            if not node or not self.is_valid:
                return

            inorder(node.left)  # 左

            # 中：检查当前节点
            if self.prev_val is not None and node.val <= self.prev_val:
                self.is_valid = False
                return
            self.prev_val = node.val

            inorder(node.right)  # 右

        inorder(root)
        return self.is_valid
